phase1.code:
#include <iostream>
#include <string>
#include <stdexcept>

// --- Custom Exception Classes ---

class GameException : public std::exception {
private:
    std::string message;

public:
    GameException(const std::string& msg) : message(msg) {}

    const char* what() const noexcept override {
        return message.c_str();
    }
};

class PlayerNotFoundException : public GameException {
public:
    PlayerNotFoundException(const std::string& name) 
        : GameException("Player '" + name + "' not found!") {}
};

class InvalidHealthException : public GameException {
public:
    InvalidHealthException(int health) 
        : GameException("Invalid health value: " + std::to_string(health)) {}
};

class InsufficientGoldException : public GameException {
private:
    int needed;
    int available;

public:
    InsufficientGoldException(int need, int have) 
        : GameException("Need " + std::to_string(need) + " gold, but have " + std::to_string(have)),
          needed(need), available(have) {}

    int getNeeded() const { return needed; }
    int getAvailable() const { return available; }
};

// --- Game functions that throw custom exceptions ---

void findPlayer(const std::string& name) {
    if (name != "Hero") {
        throw PlayerNotFoundException(name);
    }
    std::cout << "Player " << name << " found!" << std::endl;
}

void setHealth(int health) {
    if (health < 0 || health > 100) {
        throw InvalidHealthException(health);
    }
    std::cout << "Health set to " << health << std::endl;
}

void purchaseItem(int cost, int gold) {
    if (cost > gold) {
        throw InsufficientGoldException(cost, gold);
    }
    std::cout << "Purchased item for " << cost << " gold!" << std::endl;
}

int main() {
    std::cout << "=== Custom Exception Classes ===" << std::endl;

    // 1. PlayerNotFound
    std::cout << "\n--- PlayerNotFoundException ---" << std::endl;
    try {
        findPlayer("Gandalf");
    } catch (const PlayerNotFoundException& e) {
        std::cout << "❌ " << e.what() << std::endl;
    }

    // 2. InvalidHealth
    std::cout << "\n--- InvalidHealthException ---" << std::endl;
    try {
        setHealth(150);
    } catch (const InvalidHealthException& e) {
        std::cout << "❌ " << e.what() << std::endl;
    }

    try {
        setHealth(75);  // Valid
    } catch (const InvalidHealthException& e) {
        std::cout << "❌ " << e.what() << std::endl;
    }

    // 3. InsufficientGold
    std::cout << "\n--- InsufficientGoldException ---" << std::endl;
    try {
        purchaseItem(100, 50);
    } catch (const InsufficientGoldException& e) {
        std::cout << "❌ " << e.what() << std::endl;
        std::cout << "   Need: " << e.getNeeded() << ", Have: " << e.getAvailable() << std::endl;
    }

    // 4. Successful operation
    std::cout << "\n--- Successful ---" << std::endl;
    try {
        findPlayer("Hero");
        purchaseItem(30, 50);
    } catch (const GameException& e) {
        std::cout << "❌ " << e.what() << std::endl;
    }

    // 5. Catch by base class
    std::cout << "\n--- Catch by Base Class ---" << std::endl;
    try {
        throw InvalidHealthException(-10);
    } catch (const GameException& e) {
        std::cout << "❌ Caught by GameException: " << e.what() << std::endl;
    } catch (const std::exception& e) {
        std::cout << "❌ Caught by std::exception: " << e.what() << std::endl;
    }

    std::cout << "\n--- Custom Exception Benefits ---" << std::endl;
    std::cout << "✅ Clear error messages" << std::endl;
    std::cout << "✅ Domain-specific errors" << std::endl;
    std::cout << "✅ Can store additional data" << std::endl;
    std::cout << "✅ Type-safe error handling" << std::endl;

    return 0;
}

