phase2.explanation:
Your exception class doesn't inherit from `std::exception`!

**What's happening:**
1. `MyException` doesn't inherit from `std::exception`
2. `catch (const std::exception&)` won't catch it
3. The exception is unhandled → program terminates

**The fix:**
```cpp
class MyException : public std::exception {
private:
    std::string message;

public:
    MyException(const std::string& msg) : message(msg) {}

    const char* what() const noexcept override {
        return message.c_str();
    }
};
```

**PlusPlus-chan says:**
"All custom exceptions should inherit from `std::exception`. That's the standard."

phase3.solution:
#include <iostream>
#include <string>
#include <stdexcept>

class GameException : public std::exception {
private:
    std::string message;

public:
    GameException(const std::string& msg) : message(msg) {}

    const char* what() const noexcept override {
        return message.c_str();
    }
};

class InventoryFullException : public GameException {
private:
    std::string itemName;
    int maxSize;

public:
    InventoryFullException(const std::string& item, int max) 
        : GameException("Inventory full! Cannot add '" + item + "' (max: " + std::to_string(max) + ")"),
          itemName(item), maxSize(max) {}

    std::string getItemName() const { return itemName; }
    int getMaxSize() const { return maxSize; }
};

class ItemNotFoundException : public GameException {
private:
    std::string itemName;

public:
    ItemNotFoundException(const std::string& item) 
        : GameException("Item '" + item + "' not found!"),
          itemName(item) {}

    std::string getItemName() const { return itemName; }
};

class NotEnoughGoldException : public GameException {
private:
    int cost;
    int gold;

public:
    NotEnoughGoldException(int c, int g) 
        : GameException("Not enough gold! Need " + std::to_string(c) + ", have " + std::to_string(g)),
          cost(c), gold(g) {}

    int getCost() const { return cost; }
    int getGold() const { return gold; }
};

int main() {
    std::cout << "=== Custom Exceptions ===" << std::endl;

    try {
        throw InventoryFullException("Sword", 10);
    } catch (const InventoryFullException& e) {
        std::cout << "❌ " << e.what() << std::endl;
        std::cout << "   Item: " << e.getItemName() << ", Max: " << e.getMaxSize() << std::endl;
    }

    try {
        throw ItemNotFoundException("Potion");
    } catch (const ItemNotFoundException& e) {
        std::cout << "\n❌ " << e.what() << std::endl;
        std::cout << "   Item: " << e.getItemName() << std::endl;
    }

    try {
        throw NotEnoughGoldException(100, 30);
    } catch (const NotEnoughGoldException& e) {
        std::cout << "\n❌ " << e.what() << std::endl;
        std::cout << "   Cost: " << e.getCost() << ", Gold: " << e.getGold() << std::endl;
    }

    std::cout << "\n✅ All exceptions tested!" << std::endl;

    return 0;
}
